INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e2ae19e5-84e7-4fb9-b89e-08b610b7c872',
  '00000000-0000-0000-0000-000000000001',
  $escape$webpack Asset Handling — Images, Fonts, SVGs, and Content Hashing$escape$,
  $escape$webpack 5 replaces `file-loader` and `url-loader` with built-in Asset Modules. Four types cover every static asset need: `asset/resource` emits a separate file and returns its URL; `asset/inline` base64-encodes the asset into the bundle; `asset/source` injects raw content as a string; `asset` auto-picks between resource and inline based on a configurable size threshold (default 8kb).

For SVGs, set type `asset/source` to get the raw markup — enabling inline SVG injection and CSS fill manipulation at runtime. For fonts, `asset/resource` with a generator filename keeps them in a dedicated output directory.

Content hashing is controlled via `output.filename` and `generator.filename` using the `[contenthash]` substitution. webpack recomputes this hash only when the file's content changes, so unchanged assets retain their hash across builds — maximizing CDN cache hits while busting stale files automatically. Use `[contenthash:8]` for shorter hashes in filenames.$escape$,
  $escape$// webpack.config.js
module.exports = {
  output: {
    filename: '[name].[contenthash:8].js',
    assetModuleFilename: 'assets/[name].[contenthash:8][ext]',
  },
  module: {
    rules: [
      {
        test: /\.(png|jpe?g|gif|webp)$/i,
        type: 'asset',
        parser: { dataUrlCondition: { maxSize: 8 * 1024 } },
      },
      {
        test: /\.svg$/i,
        type: 'asset/source',
      },
      {
        test: /\.(woff2?|ttf|eot)$/i,
        type: 'asset/resource',
        generator: { filename: 'fonts/[name].[contenthash:8][ext]' },
      },
    ],
  },
};$escape$,
  $escape$javascript$escape$,
