INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd15a1929-a4c2-4609-bdab-93c8cd6b857c',
  '00000000-0000-0000-0000-000000000001',
  $escape$webpack Production Optimization — Minification, Compression, and Tree Shaking$escape$,
  $escape$webpack's production mode (`mode: 'production'`) enables TerserPlugin for JS minification by default, but you can tune it. Set `compress.drop_console: true` to strip console calls and `mangle.toplevel: true` for aggressive identifier renaming. For CSS, pair `css-minimizer-webpack-plugin` with `MiniCssExtractPlugin` — the default `cssnano` preset handles vendor prefix removal and rule merging.

Tree shaking requires ES modules — CommonJS `require()` blocks it entirely. Mark your package as side-effect-free with `"sideEffects": false` in `package.json`, or enumerate affected files (e.g. global CSS imports) so webpack's `usedExports` and `providedExports` analyses can prune safely.

For compression, `CompressionPlugin` generates `.gz` and `.br` static assets at build time — your CDN or nginx serves the pre-compressed file directly, bypassing runtime encoding. Brotli (`algorithm: 'brotliCompress'`) achieves 15–25% smaller output than gzip on text assets. Set `threshold: 10240` to skip compressing files under 10 KB where overhead exceeds savings.$escape$,
  $escape$// webpack.config.js
const TerserPlugin = require('terser-webpack-plugin');
const CssMinimizerPlugin = require('css-minimizer-webpack-plugin');
const CompressionPlugin = require('compression-webpack-plugin');

module.exports = {
  mode: 'production',
  optimization: {
    minimizer: [
      new TerserPlugin({
        terserOptions: {
          compress: { drop_console: true },
          mangle: { toplevel: true },
        },
      }),
      new CssMinimizerPlugin(),
    ],
    usedExports: true,
    sideEffects: true,
  },
  plugins: [
    new CompressionPlugin({ algorithm: 'brotliCompress', threshold: 10240 }),
    new CompressionPlugin({ algorithm: 'gzip', threshold: 10240 }),
  ],
};$escape$,
  $escape$javascript$escape$,
