INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '810518df-1fea-48c8-8faf-309079094995',
  '00000000-0000-0000-0000-000000000001',
  $escape$webpack Monorepo Support — Workspace Packages, Shared Configs, and Turborepo Integration$escape$,
  $escape$webpack doesn't natively understand workspace packages, but it resolves them correctly when you configure `resolve.alias` or rely on Node's module resolution with symlinks. Set `resolve.symlinks: true` (default) so webpack follows pnpm/yarn workspace symlinks to their real disk locations — critical for source maps and HMR to work correctly across packages.

For shared webpack configs in a monorepo, use `webpack-merge` to compose a base config from a root `packages/webpack-config` package, then extend per-app. Each app's `webpack.config.js` imports and merges the shared preset.

When layering Turborepo on top, Turborepo's `pipeline` caches webpack build outputs (the `dist/` directory) keyed by input hashes. Define `outputs: ["dist/**"]` in `turbo.json` so Turborepo knows what to restore. Turborepo doesn't replace webpack — it caches its artifacts. For type-only packages consumed by webpack's TypeScript loader (`ts-loader` or `babel-loader`), add them to `dependsOn` in the pipeline so they build before webpack runs.$escape$,
  $escape$// packages/webpack-config/index.js
const { merge } = require('webpack-merge');

module.exports = (appOverrides) => merge({
  resolve: {
    symlinks: true,
    extensions: ['.ts', '.tsx', '.js'],
  },
  module: {
    rules: [{
      test: /\.tsx?$/,
      use: 'babel-loader',
      exclude: /node_modules/,
    }],
  },
}, appOverrides);

// apps/dashboard/webpack.config.js
const base = require('webpack-config');
module.exports = base({ entry: './src/index.tsx', output: { path: __dirname + '/dist' } });$escape$,
  $escape$javascript$escape$,
